import os
from flask import Flask, request, redirect, url_for, render_template, session
from flask_oauthlib.client import OAuth

app = Flask(__name__)
app.secret_key = 'development key'

oauth = OAuth()

@app.route('/login')
def login():
    return oauth.google.authorize(callback=url_for('authorized', _external=True))


@app.route('/logout')
def logout():
    session['access_token'] = None
    return redirect(url_for('index'))


@app.route('/authorized')
def authorized():
    resp = oauth.google.get('userinfo')
    if resp.ok:
        session['access_token'] = (resp.data)['access_token']

    return redirect(url_for('index'))


@app.route('/')
def index():
    if 'access_token' in session:
        resp = oauth.google.get('https://www.googleapis.com/oauth2/v1/userinfo')
        print (resp)
        if resp.ok:
            return render_template('index.html', userinfo=resp.data)

    return redirect(url_for('login'))


if __name__ == '__main__':
    app.run()